"use client";

import { useEffect, useState } from "react";
import { supabase } from "@/app/lib/supabase";

const htmlBase64 = "";

function decodeHtml() {
  const binary = window.atob(htmlBase64);
  const bytes = Uint8Array.from(binary, (char) => char.charCodeAt(0));
  return new TextDecoder("utf-8").decode(bytes);
}

export default function Page() {
  useEffect(() => {
    async function applySupabaseProfile() {
      const { data: sessionData } = await supabase.auth.getSession();
      const user = sessionData.session?.user;
      if (!user) return null;

      const { data: profile } = await supabase
        .from("profiles")
        .select("role, is_premium")
        .eq("id", user.id)
        .single();

      const role = profile?.role || "player";
      const isPremium = !!profile?.is_premium;

      try {
        const w = window as any;
        if (role === "architect" && typeof w.activateArchitectMode === "function") {
          w.activateArchitectMode(user.email || "Architect");
          return { role, isPremium: true };
        }

        if (w.state) {
          w.state.role = role;
          w.state.isPremium = isPremium;
          if (isPremium) {
            w.state.levelPaymentUnlocked = true;
            w.state.levelPaywallSeen = true;
          }
          if (typeof w.save === "function") w.save();
          if (typeof w.render === "function") w.render();
          if (typeof w.applyPathMenu === "function") w.applyPathMenu();
        }
      } catch {}

      return { role, isPremium };
    }

    (window as any).__showSupabaseLoginForm = function () {
      const box = document.querySelector(".level-login-options");
      if (!box) return;

      box.innerHTML = `
        <div style="display:grid;gap:9px;margin-top:10px">
          <input id="supabaseEmail" type="email" placeholder="EMAIL" autocomplete="email" style="
            width:100%;padding:12px 10px;background:rgba(2,8,24,.96);border:1px solid #6d9eff;color:#dff;
            font-weight:900;text-align:center;box-shadow:0 0 10px rgba(40,114,255,.85);outline:none;
            clip-path:polygon(4% 0,96% 0,100% 20%,100% 80%,96% 100%,4% 100%,0 80%,0 20%);
          " />
          <input id="supabasePassword" type="password" placeholder="PASSWORD" autocomplete="current-password" style="
            width:100%;padding:12px 10px;background:rgba(2,8,24,.96);border:1px solid #6d9eff;color:#dff;
            font-weight:900;text-align:center;box-shadow:0 0 10px rgba(40,114,255,.85);outline:none;
            clip-path:polygon(4% 0,96% 0,100% 20%,100% 80%,96% 100%,4% 100%,0 80%,0 20%);
          " />
          <button onclick="window.__supabaseLoginFromPaywall()" style="
            width:100%;padding:13px 10px;background:rgba(0,120,255,.25);border:1px solid #8fefff;color:#fff;
            font-weight:900;box-shadow:0 0 12px #65d8ff;cursor:pointer;
            clip-path:polygon(5% 0,95% 0,100% 18%,100% 82%,95% 100%,5% 100%,0 82%,0 18%);
          ">SIGN IN</button>
          <button onclick="window.__restoreLoginChoices()" style="
            width:100%;padding:10px;background:rgba(2,8,24,.55);border:1px solid rgba(143,239,255,.55);color:#94f9ff;
            font-weight:900;cursor:pointer;
          ">BACK</button>
        </div>
      `;
    };

    (window as any).__restoreLoginChoices = function () {
      const box = document.querySelector(".level-login-options");
      if (!box) return;
      box.innerHTML = `
        <button onclick="loginLevelGate('Google')">CONTINUE WITH GOOGLE</button>
        <button onclick="loginLevelGate('Apple')">CONTINUE WITH APPLE</button>
        <button onclick="loginLevelGate('Email')">CONTINUE WITH EMAIL</button>
      `;
    };

    (window as any).__supabaseLoginFromPaywall = async function () {
      const email = ((document.getElementById("supabaseEmail") as HTMLInputElement | null)?.value || "").trim();
      const password = (document.getElementById("supabasePassword") as HTMLInputElement | null)?.value || "";

      if (!email || !password) {
        alert("Enter email and password.");
        return;
      }

      const { error } = await supabase.auth.signInWithPassword({ email, password });
      if (error) {
        alert(error.message);
        return;
      }

      const profile = await applySupabaseProfile();
      const w = window as any;

      try {
        if (profile?.role === "architect") {
          if (typeof w.hideLevelPaywall === "function") w.hideLevelPaywall();
          if (typeof w.showSystemMessage === "function") {
            w.showSystemMessage("ARCHITECT ACCESS", "ROLE VERIFIED", "Paywall bypass active. Architect Console unlocked.", "rankup", 0, true);
          }
          return;
        }

        if (w.state) {
          w.state.levelLoginUnlocked = true;
          w.state.levelLoginProvider = "Email";
          if (typeof w.save === "function") w.save();
        }

        if (typeof w.showSystemMessage === "function") {
          w.showSystemMessage("LOGIN ACCEPTED", "IDENTITY VERIFIED", "Email account connected. Complete access to continue leveling.", "rankup", 0, true);
        }

        if (profile?.isPremium) {
          if (typeof w.levelPaywallStep === "function") w.levelPaywallStep("success");
        } else if (typeof w.levelPaywallStep === "function") {
          w.levelPaywallStep("pay");
        }
      } catch {}
    };

    (window as any).loginWithEmail = async function (email: string, password: string) {
      const { error } = await supabase.auth.signInWithPassword({ email, password });
      if (error) {
        alert(error.message);
        return;
      }
      await applySupabaseProfile();
      window.location.reload();
    };

    const html = decodeHtml();
    document.open();
    document.write(html);
    document.close();


    const installPremiumGateFix = () => {
      const w = window as any;

      const isPaid = () => {
        try {
          const ls = localStorage.getItem("questAppV1");
          const saved = ls ? JSON.parse(ls) : {};
          return !!(
            w.state?.isPremium ||
            w.state?.levelPaymentUnlocked ||
            saved?.isPremium ||
            saved?.levelPaymentUnlocked
          );
        } catch {
          return !!(w.state?.isPremium || w.state?.levelPaymentUnlocked);
        }
      };

      const markPaid = () => {
        try {
          const current = w.state || {};
          current.isPremium = true;
          current.levelPaymentUnlocked = true;
          current.levelPaywallSeen = true;
          w.state = current;

          try {
            const savedRaw = localStorage.getItem("questAppV1");
            const saved = savedRaw ? JSON.parse(savedRaw) : {};
            saved.isPremium = true;
            saved.levelPaymentUnlocked = true;
            saved.levelPaywallSeen = true;
            localStorage.setItem("questAppV1", JSON.stringify({ ...saved, ...current }));
          } catch {
            localStorage.setItem("questAppV1", JSON.stringify(current));
          }

          if (typeof w.save === "function") w.save();
          if (typeof w.render === "function") w.render();
        } catch {}
      };

      const params = new URLSearchParams(window.location.search);
      if (params.get("payment") === "success") {
        markPaid();
        try {
          if (typeof w.showSystemMessage === "function") {
            w.showSystemMessage(
              "ASCENSION UNLOCKED",
              "PAYMENT CONFIRMED",
              "Your pass is active. Level restrictions removed.",
              "rankup",
              0,
              true
            );
          }
          if (typeof w.levelPaywallStep === "function") w.levelPaywallStep("success");
          if (typeof w.hideLevelPaywall === "function") w.hideLevelPaywall();
        } catch {}
      }

      if (typeof w.showLevelPaywall === "function" && !w.showLevelPaywall.__premiumWrapped) {
        const originalShow = w.showLevelPaywall;
        const wrappedShow = function () {
          if (isPaid()) {
            markPaid();
            try { if (typeof w.hideLevelPaywall === "function") w.hideLevelPaywall(); } catch {}
            return;
          }
          return originalShow.apply(null, Array.from(arguments) as any);
        };
        (wrappedShow as any).__premiumWrapped = true;
        w.showLevelPaywall = wrappedShow;
      }

      if (typeof w.payLevelGate === "function" && !w.payLevelGate.__premiumWrapped) {
        const originalPay = w.payLevelGate;
        const wrappedPay = async function () {
          if (isPaid()) {
            markPaid();
            try { if (typeof w.levelPaywallStep === "function") w.levelPaywallStep("success"); } catch {}
            return;
          }
          return originalPay.apply(null, Array.from(arguments) as any);
        };
        (wrappedPay as any).__premiumWrapped = true;
        w.payLevelGate = wrappedPay;
      }
    };

    installPremiumGateFix();
    const premiumGateFixTimer = window.setInterval(installPremiumGateFix, 250);
    window.setTimeout(() => window.clearInterval(premiumGateFixTimer), 6000);

    setTimeout(() => {
      applySupabaseProfile();
      installPremiumGateFix();
    }, 500);
  }, []);

  return null;
}
